B.ZW=new A.m(B.as,"\u2708\ufe0f S\u0131nav \u0130pucu",'\xc7oktan se\xe7meli sorularda ipucu ara:\n\u2022 \xd6zne bir **nesne** ise (ki\u015fi de\u011filse), b\xfcy\xfck ihtimalle edilgen \xe7at\u0131 do\u011frudur.\n\u2022 "\u2026\u2026\u2026\u2026 by the engine" \u2192 edilgen form gerekir.\n\u2022 Modal fiil + edilgen: **must be + ge\xe7mi\u015f zaman ortac\u0131** kal\u0131b\u0131 havac\u0131l\u0131k bak\u0131m \u0130ngilizcesinde en yayg\u0131n yap\u0131d\u0131r.',null,null,null)
