B.RN=new A.a4("The aircraft may depart after all checks are completed.","T\xfcm kontroller tamamland\u0131ktan sonra u\xe7ak kalkabilir.","may depart")
B.RI=new A.a4("Contaminated parts must not be reinstalled without inspection.","Kirlenmi\u015f par\xe7alar incelenmeden yeniden tak\u0131lmamal\u0131d\u0131r.","must not be reinstalled")
B.a7l=s([B.Qy,B.SL,B.RN,B.RI],t.l)
B.XU=new A.m(B.L,"Ba\u011flamda Modal Fiiller",null,B.a7l,null,null)
B.a0L=new A.m(B.as,"\u2708\ufe0f S\u0131nav \u0130pucu",'Modal sorular\u0131nda yayg\u0131n tuzaklar:\n\u2022 "must checking" \u2192 YANLI\u015e (modal + yal\u0131n fiil, -ing de\u011fil)\n\u2022 "should to inspect" \u2192 YANLI\u015e (modal sonras\u0131nda "to" gelmez)\n\u2022 "must performed" \u2192 YANLI\u015e (edilgen i\xe7in "be" gerekli: must **be** performed)\n\nModal fiil + bo\u015fluk g\xf6r\xfcnce sor: etken mi yoksa edilgen anlam m\u0131 gerekiyor?',null,null,null)
