B.Y4=new A.m(B.as,"\u2708\ufe0f S\u0131nav \u0130pucu",'G\xfcvenlik ekipman\u0131 ile kullan\u0131lan temel fiiller:\n\u2022 **don** = giymek (can yele\u011fi, oksijen maskesi) \u2014 resmi havac\u0131l\u0131k terimi\n\u2022 **deploy** = otomatik etkinle\u015ftirmek (tahliye kayal\u011f\u0131, oksijen maskesi)\n\u2022 **arm** = otomatik a\xe7\u0131l\u0131m moduna ayarlamak (kap\u0131 kayal\u011f\u0131)\n\u2022 **discharge** = s\xf6nd\xfcr\xfcc\xfc maddeyi salmak\n\u2022 **arm/disarm** kap\u0131lar = kalk\u0131\u015f \xf6ncesi/var\u0131\u015f sonras\u0131 kabin ekibi eylemi\n\nResmi s\u0131nav yan\u0131tlar\u0131nda "put on" yerine her zaman **don** kullan\u0131n.',null,null,null)
