B.QZ=new A.a4("OVC008 means overcast cloud at 800 feet above aerodrome level.","OVC008, ta\u015f\u0131t alan\u0131 seviyesinin 800 feet \xfczerinde tam kapal\u0131 bulut anlam\u0131na gelir.","overcast")
B.Ri=new A.a4("TSRA in a METAR indicates thunderstorm with rain in the vicinity.","METAR'daki TSRA, civarda \u015fim\u015fekli ya\u011f\u0131\u015f oldu\u011funu g\xf6sterir.","TSRA")
B.SQ=new A.a4("BECMG 0912 SCT020 means cloud will gradually become scattered at 2,000 feet between 09 and 12 UTC.","BECMG 0912 SCT020, bulutun 09\u201312 UTC aras\u0131nda kademeli olarak 2000 feet'te par\xe7al\u0131 hale gelece\u011fi anlam\u0131na gelir.","BECMG")
