B.Yh=new A.m(B.x,"\u0130leri klirenslar birden fazla unsuru birle\u015ftirir","\u0130leri d\xfczeyde, ATC kliranslar\u0131 tek bir iletimde irtifa, y\xf6n, h\u0131z, frekans ve transponder gibi birden fazla e\u015f zamanl\u0131 talimat i\xe7erir. Bunlar\u0131 do\u011fru analiz etmek ve tamamlamak, uzman d\xfczey s\u0131navlarda test edilen \xfcst d\xfczey bir beceridir.",null,null,null)
B.Y5=new A.m(B.v,"\ud83d\uddfc Okyanus & Karma\u015f\u0131k Klirans Unsurlar\u0131",'**Oceanic clearance:** "THY1 is cleared to New York JFK via track Bravo, flight level 360, Mach 0.84, squawk 2341"\n\n**Complex enroute:** "THY456, cross TURPO at or above FL280, then direct EMEVI, reduce to Mach 0.80"\n\n**Conditional clearance:** "Behind the departing B777, line up runway 34L and wait"\n\u2014 Always read back: **type of aircraft + condition + instruction**\n\n**SELCAL** \u2014 Selective Calling system for oceanic comms\n**HF** \u2014 High Frequency radio (used in oceanic areas beyond VHF range)',null,null,null)
B.a1D=new A.m(B.v,"\ud83d\udd04 Bekleme Klirans Dili",'"THY123, hold at TURPO as published, expect approach in 20 minutes"\n"\u2026\u2026\u2026\u2026 to the right on the 150 radial, 1-minute legs"\n\n**Key holding terms:**\n\u2022 **Inbound course** \u2014 heading toward the fix during holding\n\u2022 **Outbound leg** \u2014 time/distance spent flying away from fix\n\u2022 **Expect further clearance (EFC)** \u2014 time pilot can expect to leave the hold\n\u2022 **Published hold** \u2014 charted holding pattern; use standard values\n\u2022 "**Left / right turns**" \u2014 direction of turns in the hold',null,null,null)
B.QX=new A.a4("THY123, cross TURPO at or above FL260, then direct EMEVI, Mach 0.82.","THY123, TURPO'yu FL260 veya \xfczerinde ge\xe7in, ard\u0131ndan EMEVI'ye direkt, Mach 0.82.","cross TURPO at or above")
B.RA=new A.a4("Behind the departing A330, line up runway 18L and wait.","Kalkan A330'un arkas\u0131nda, pist 18L'ye s\u0131raya girin ve bekleyin.","Behind the departing")
B.So=new A.a4("Hold at VESAS on the 270 radial, right turns, 1-minute legs, expect approach at 1430.","VESAS'ta 270 radyal \xfczerinde, sa\u011f turlar, 1 dakikal\u0131k bacaklar, saat 14:30'da yakla\u015fma bekleniyor.","Hold at")
B.a8v=s([B.QX,B.RA,B.So],t.l)
B.Y0=new A.m(B.L,"\u0130leri Klirans \xd6rnekleri",null,B.a8v,null,null)
B.a1r=new A.m(B.as,"\u2708\ufe0f \u0130leri S\u0131nav \u0130pu\xe7lar\u0131",'Ko\u015fulllu kliranslar \u2014 her zaman \u015funlar\u0131 belirleyin:\n1. **Ko\u015ful** \u2014 hangi u\xe7ak / ne zaman\n2. **Talimat** \u2014 ne yap\u0131lacak\n3. **Tekrar** ko\u015fulu i\xe7ermelidir: "Behind the B777 on final, cleared to land, THY456"\n\nOkyanus kliranslar\u0131 her zaman \u015funlar\u0131 i\xe7erir: track harfi + FL + Mach numaras\u0131 + squawk\n\nEFC (Expect Further Clearance) bekleme d\xf6ng\xfcs\xfcnden ayr\u0131lma klirans\u0131 **de\u011fildir** \u2014 pilot ger\xe7ek klirans\u0131 beklemelidir.',null,null,null)
