B.Zy=new A.m(B.x,"Operations Manual (OM) dili","Havayolu operasyon el kitaplar\u0131 (OM-A: Genel, OM-B: U\xe7u\u015f Operasyonlar\u0131) karma\u015f\u0131k yasal ve teknik dil i\xe7erir. Bu dili anlamak; kurallar\u0131 do\u011fru yorumlamak ve s\u0131navda ba\u015far\u0131l\u0131 olmak i\xe7in \u015fartt\u0131r.",null,null,null)
