B.a20=new A.m(B.x,"Tahliye ileti\u015fimi hayat kurtar\u0131r","Acil tahliyede saniyeler kritiktir. Kabin ekibinin kulland\u0131\u011f\u0131 komutlar\u0131n net, standart ve y\xfcksek sesle verilmesi gerekir. ICAO ve havayolu SOPlar\u0131 bu ifadeleri belirler.",null,null,null)
B.a0j=new A.m(B.v,"Standart Tahliye Komutlar\u0131",'"EVACUATE! EVACUATE! EVACUATE!"\n"RELEASE SEATBELTS! LEAVE EVERYTHING! GET OUT!"\n"COME THIS WAY! THIS EXIT!" (i\u015flevsel \xe7\u0131k\u0131\u015ftayken)\n"COME THIS WAY!" (fonksiyonel olmayan \xe7\u0131k\u0131\u015ftayken y\xf6nlendirme)\n"JUMP AND SLIDE!" / "STEP OFF THE SLIDE!"\n"MOVE AWAY FROM THE AIRCRAFT! MOVE AWAY!"\n\n**Kapal\u0131 \xe7\u0131k\u0131\u015fta:**\n"GET BACK! GET BACK! COME THIS WAY!" (di\u011fer \xe7\u0131k\u0131\u015fa y\xf6nlendirme)',null,null,null)
