B.a_q=new A.m(B.x,"Havac\u0131l\u0131kta muayene t\xfcrleri","Havac\u0131l\u0131k bak\u0131m\u0131nda farkl\u0131 derinlikte muayene t\xfcrleri tan\u0131mlanm\u0131\u015ft\u0131r. Do\u011fru terminolojiyi bilmek, i\u015f emrini (work order) ve sonu\xe7 raporunu do\u011fru yazmak i\xe7in \u015fartt\u0131r.",null,null,null)
B.Ya=new A.m(B.v,"Muayene T\xfcrleri","**General Visual Inspection (GVI):**\n\u2014 Geni\u015f alanda, eri\u015fim gerekmeksizin yap\u0131lan genel g\xf6rsel muayene\n\u2014 Hasar\u0131, ar\u0131zay\u0131, d\xfczensizli\u011fi tespit etmek i\xe7in\n\n**Detailed Inspection (DET):**\n\u2014 Yak\u0131n mesafeden, genellikle ayd\u0131nlatma ve b\xfcy\xfctme yard\u0131m\u0131yla\n\u2014 Belirli bir alana odaklan\u0131r\n\n**Special Detailed Inspection (SDI):**\n\u2014 NDT (Non-Destructive Testing) teknikleri i\xe7erir\n\u2014 Borescope, eddy current, ultrasonic, X-ray\n\n**Operational Check:**\n\u2014 Sistemin tasar\u0131m fonksiyonunu ger\xe7ekle\u015ftirip ger\xe7ekle\u015ftirmedi\u011fini do\u011frular\n\n**Functional Check:**\n\u2014 Belirli fonksiyonun quantitative (say\u0131sal) olarak do\u011frulanmas\u0131",null,null,null)
B.a9P=s(["a close-up inspection with magnifying equipment","a broad-area visual check without opening access panels","an NDT technique using eddy current","a quantitative check of system performance"],t.s)
